import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';
import { AWS_ICON_CATEGORIES, SERVICE_MAPPINGS } from '../services/IconResolver';

// Add these constants from IconResolver.js
const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const DEFAULT_ROCKET = `${S3_ROCKET_PATH}/rocket1.png`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

const GameCanvas = () => {
  // First, declare all state
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);
  const [currentInstructionIndex, setCurrentInstructionIndex] = useState(0);
  const [selectedRocket, setSelectedRocket] = useState(() => {
    const savedRocket = localStorage.getItem('selectedRocket');
    return savedRocket || null;
  });
  const [showNameModal, setShowNameModal] = useState(true);
  const [tempPlayerName, setTempPlayerName] = useState('');
  const [nameError, setNameError] = useState('');
  const [playerName, setPlayerName] = useState(() => {
    const savedName = localStorage.getItem('playerName');
    return savedName || '';
  });
  const [rocketPosition, setRocketPosition] = useState({ x: 375, y: 550 });

  // Modify the instructions state initialization
  const [instructions] = useState(() => {
    const getRandomCategories = () => {
      const categories = Object.keys(AWS_ICON_CATEGORIES);
      const shuffled = [...categories].sort(() => 0.5 - Math.random());
      return shuffled.slice(0, 1);
    };

    return getRandomCategories().map(category => {
      const displayName = category.split('_')
        .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(' ');

      return {
        text: `Shoot the ${displayName} icons!`,
        category: AWS_ICON_CATEGORIES[category],
        displayName: displayName // Add this to keep track of the display name
      };
    });
  });

  // Generate iconTypes based on the selected categories
  const [iconTypes] = useState(() => {
    return instructions.reduce((acc, instruction) => {
      const categoryServices = Object.entries(SERVICE_MAPPINGS)
        .filter(([_, path]) => path.includes(instruction.category))
        .map(([name, path]) => ({
          path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
          name: name
        }));

      acc[instruction.category] = categoryServices;
      return acc;
    }, {});
  });

  // Then declare refs and other setup code
  const canvasRef = useRef(null);

  // We'll keep arrays for icons, bullets, and feedback in refs to avoid
  // re-rendering the whole component every time they update.
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);
  const feedbacksRef = useRef([]);

  // Images for the gun and bullets
  const rocketImage = useRef(new Image());

  // Initialize rocket image
  useEffect(() => {
    rocketImage.current.src = selectedRocket;
  }, [selectedRocket]); // Update when selectedRocket changes

  const fireballImage = new Image();
  fireballImage.src = FIREBALL_PATH;

  // Gun info
  const gunRef = useRef({
    x: 400 - 25, // center of an 800px width minus half the gun width
    y: 800 - 100, // Adjust this value to move the rocket closer to the bottom
    width: 120,
    height: 120,
  });

  // Function to get random X
  const getRandomX = () => {
    const canvas = canvasRef.current;
    return Math.floor(Math.random() * (canvas.width - 50));
  };

  // Add refs to track initialization and category change status
  const isInitializing = useRef(false);
  const isChangingCategory = useRef(false);

  const loadIcons = async () => {
    if (!gameStarted || !currentCategory) {
      console.log("Game not started yet or no category set, skipping loadIcons");
      return;
    }

    if (isChangingCategory.current) {
      console.log("Category change in progress, skipping loadIcons");
      return;
    }

    console.log(`loadIcons called for category: ${currentCategory.displayName}`);
    iconsRef.current = [];
    const positions = [];

    try {
      // Get all icons for current category
      const categoryIcons = Object.entries(SERVICE_MAPPINGS)
        .filter(([_, path]) => path.includes(currentCategory.category))
        .map(([name, path]) => ({
          path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
          name: name,
          category: currentCategory.category
        }));

      // Get all icons from other categories (excluding current category)
      const otherCategoryIcons = Object.entries(SERVICE_MAPPINGS)
        .filter(([_, path]) => !path.includes(currentCategory.category))
        .map(([name, path]) => ({
          path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
          name: name,
          category: path.split('/')[1] // Extract category from path
        }));

      // For current category: Get 4 icons (with possible repeats if less than 4 available)
      let selectedCategoryIcons = [];
      if (categoryIcons.length <= 4) {
        // If we have less than 4 icons, repeat icons until we have 4
        while (selectedCategoryIcons.length < 4) {
          selectedCategoryIcons.push(
            ...categoryIcons.slice(0, 4 - selectedCategoryIcons.length)
          );
        }
      } else {
        // If we have more than 4 icons, randomly select 4 unique ones
        const shuffled = [...categoryIcons].sort(() => 0.5 - Math.random());
        selectedCategoryIcons = shuffled.slice(0, 4);
      }

      // For other categories: Get 6 random unique icons from different categories
      const selectedOtherIcons = [];
      const usedCategories = new Set();

      // Build a mapping of categories to their icons
      const categoryIconMap = otherCategoryIcons.reduce((acc, icon) => {
        if (!acc[icon.category]) {
          acc[icon.category] = [];
        }
        acc[icon.category].push(icon);
        return acc;
      }, {});

      const availableCategories = Object.keys(categoryIconMap).filter(
        (cat) => cat !== currentCategory.category
      );

      // Shuffle the categories
      const shuffledCategories = availableCategories.sort(() => 0.5 - Math.random());

      for (let i = 0; i < shuffledCategories.length && selectedOtherIcons.length < 6; i++) {
        const category = shuffledCategories[i];

        if (usedCategories.has(category)) {
          continue;
        }

        const iconsInCategory = categoryIconMap[category];

        if (iconsInCategory.length > 0) {
          // Randomly select an icon from this category
          const randomIconIndex = Math.floor(Math.random() * iconsInCategory.length);
          const icon = iconsInCategory[randomIconIndex];

          selectedOtherIcons.push(icon);
          usedCategories.add(category);
        }
      }

      // If we still need more icons, fill from remaining icons irrespective of category
      if (selectedOtherIcons.length < 6) {
        const remainingIcons = otherCategoryIcons.filter(
          (icon) => icon.category !== currentCategory.category && !selectedOtherIcons.includes(icon)
        );
        const shuffledRemainingIcons = remainingIcons.sort(() => 0.5 - Math.random());
        selectedOtherIcons.push(...shuffledRemainingIcons.slice(0, 6 - selectedOtherIcons.length));
      }

      // Log the current mission icons with more detail
      console.log(
        `Current mission category ${currentCategory.displayName} (${currentCategory.category}) = ${
          selectedCategoryIcons.map(icon => icon.name).join(', ')
        }`
      );

      // Add current category icons with random X positions
      selectedCategoryIcons.forEach((iconInfo) => {
        let x = getRandomX();
        while (positions.some((pos) => Math.abs(pos - x) < 50)) {
          x = getRandomX();
        }
        positions.push(x);

        const iconImage = new Image();
        iconImage.src = iconInfo.path;

        iconsRef.current.push({
          x,
          y: -50,
          type: iconInfo.category,
          name: iconInfo.name,
          image: iconImage,
          hit: false,
        });
      });

      // Add other category icons with random X positions
      selectedOtherIcons.forEach((iconInfo) => {
        let x = getRandomX();
        while (positions.some((pos) => Math.abs(pos - x) < 50)) {
          x = getRandomX();
        }
        positions.push(x);

        const iconImage = new Image();
        iconImage.src = iconInfo.path;

        iconsRef.current.push({
          x,
          y: -50,
          type: iconInfo.category,
          name: iconInfo.name,
          image: iconImage,
          hit: false,
        });
      });

      // Log the distraction icons
      console.log(
        `Distraction icons from other categories:\n${selectedOtherIcons
          .map(icon => `${icon.name} (${icon.category})`)
          .join('\n')}`
      );
    } catch (error) {
      console.error("Error loading icons:", error);
    }
  };

  // Show feedback (checkmark or X) and points after a shot
  const showFeedback = (x, y, isCorrect, points, iconName) => {
    feedbacksRef.current.push({
      x,
      y,
      isCorrect,
      points,
      name: iconName,
      time: Date.now(),
    });
  };

  // Check collisions and update score
  const checkCollisions = () => {
    if (!currentCategory) {
      console.warn("checkCollisions called before currentCategory is initialized");
      return;
    }

    const bullets = bulletsRef.current;
    const icons = iconsRef.current;
    const canvas = canvasRef.current;

    icons.forEach((icon, iconIndex) => {
      bulletsRef.current = bulletsRef.current.filter((bullet) => {
        if (
          bullet.x > icon.x &&
          bullet.x < icon.x + 50 &&
          bullet.y > icon.y &&
          bullet.y < icon.y + 50
        ) {
          icon.hit = true;

          if (icon.type === currentCategory.category) {
            const heightPercentage = 1 - (icon.y / canvas.height);
            const heightBonus = Math.floor(heightPercentage * 20);
            const points = 5 + heightBonus;

            setScore((prev) => {
              if (prev + points > Math.max(...highScores.map(s => s.score))) {
                showCheerleaderMessage('highScore');
              } else if (heightBonus > 15) {
                showCheerleaderMessage('goodShot');
              }
              return prev + points;
            });
            showFeedback(icon.x, icon.y, true, points, icon.name);
            playSound('correct');
            createExplosion(icon.x + 25, icon.y + 25, '#4CAF50');
          } else {
            setScore((prev) => prev - 5);
            showFeedback(icon.x, icon.y, false, -5, icon.name);
            playSound('incorrect');
          }

          icons.splice(iconIndex, 1);
          return false;
        }
        return true;
      });
    });

    if (iconsRef.current.length === 0 && timeLeft > 0) {
      playSound('levelup');
      newCategoryMission();
    }
  };

  // The main game loop, which draws everything on the canvas
  const gameLoop = () => {
    if (!gameStarted || !canvasRef.current) {
      console.log("Game not started or canvas not ready");
      return;
    }

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    // Clear the canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Debug logs (reduce frequency to avoid console spam)
    if (Math.random() < 0.01) { // Only log 1% of the time
      console.log("Game state:", {
        gameStarted,
        iconsCount: iconsRef.current.length,
        rocketLoaded: rocketImage.current?.complete,
        gunPosition: gunRef.current
      });
    }

    // Draw the rocket (gun)
    const { x: gunX, y: gunY, width, height } = gunRef.current;
    if (rocketImage.current && rocketImage.current.complete) {
      ctx.drawImage(rocketImage.current, gunX, gunY, width, height);
    }

    // Draw icons
    if (iconsRef.current.length > 0) {
      iconsRef.current.forEach((icon) => {
        if (!icon.hit && icon.image && icon.image.complete) {
          ctx.save();
          ctx.drawImage(icon.image, icon.x, icon.y, 50, 50);
          ctx.restore();
          icon.y += 0.7;
        }
      });
    }

    // Draw bullets
    bulletsRef.current.forEach((bullet) => {
      if (fireballImage && fireballImage.complete) {
        ctx.drawImage(fireballImage, bullet.x, bullet.y, 20, 20);
        bullet.y -= 5;
      }
    });

    // Remove bullets that are off-screen
    bulletsRef.current = bulletsRef.current.filter((b) => b.y > 0);

    checkCollisions();

    // Continue the game loop only if the game is still running
    if (gameStarted) {
      requestAnimationFrame(gameLoop);
    }
  };

  // Initialize gun position with debug log
  const initializeGun = () => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      gunRef.current = {
        x: canvas.width / 2 - 25,
        y: canvas.height - 100,
        width: 50,
        height: 50
      };
      console.log("Gun initialized:", gunRef.current);
    } else {
      console.log("Canvas not ready for gun initialization");
    }
  };

  // Add sound references with error handling
  const sounds = useRef({});
  const [soundsLoaded, setSoundsLoaded] = useState(false);

  // Initialize sounds with error handling
  useEffect(() => {
    const soundFiles = {
      shoot:  `${S3_BUCKET_URL}/games/sounds/pistol_sound.mp3`,
      correct: `${S3_BUCKET_URL}/games/sounds/correct_sound.mp3`,
      incorrect:`${S3_BUCKET_URL}/games/sounds/incorrect_sound.mp3`,
      levelup: `${S3_BUCKET_URL}/games/sounds/levelup.mp3`
    };

    // Create a safe audio player that won't break if files are missing
    const createSafeAudio = (path) => {
      const audio = new Audio();

      return new Promise((resolve) => {
        audio.addEventListener('error', () => {
          console.warn(`Sound file not found: ${path}`);
          resolve(null);
        });

        audio.addEventListener('canplaythrough', () => {
          resolve(audio);
        });

        // Set timeout in case the file takes too long to load
        setTimeout(() => resolve(null), 2000);

        audio.src = path;
      });
    };

    // Load all sound files with error handling
    const loadSounds = async () => {
      const loadedSounds = {};

      for (const [key, path] of Object.entries(soundFiles)) {
        loadedSounds[key] = await createSafeAudio(path);
      }

      sounds.current = loadedSounds;
      setSoundsLoaded(true);
    };

    loadSounds();

    // Set initial volume
    return () => {
      // Cleanup sounds on unmount
      Object.values(sounds.current).forEach(sound => {
        if (sound) {
          sound.pause();
          sound.src = '';
        }
      });
    };
  }, []);

  // Safe play function
  const playSound = (soundName) => {
    const sound = sounds.current[soundName];
    if (sound && !isMuted) {
      try {
        sound.currentTime = 0;
        sound.volume = 0.3;
        sound.play().catch(err => {
          console.warn(`Error playing sound ${soundName}:`, err);
        });
      } catch (err) {
        console.warn(`Error with sound ${soundName}:`, err);
      }
    }
  };

  // Add a mute toggle button to the UI
  const [isMuted, setIsMuted] = useState(false);

  const toggleMute = () => {
    setIsMuted(!isMuted);
    Object.values(sounds.current).forEach(sound => {
      if (sound) {
        sound.muted = !isMuted;
      }
    });
  };

  // Add new state and refs for particles and timer
  const [highScores, setHighScores] = useState(() => {
    const saved = localStorage.getItem('highScores');
    return saved ? JSON.parse(saved) : [];
  });
  const [gameOver, setGameOver] = useState(false);
  const particlesRef = useRef([]);

  // Add state to track if we've already handled game over
  const [gameOverHandled, setGameOverHandled] = useState(false);

  // Add state to track if game should start
  const [gameStarted, setGameStarted] = useState(false);

  // Add cleanup effect
  useEffect(() => {
    return () => {
      // Cleanup when component unmounts
      setGameStarted(false);
      setShowRocketModal(true);
    };
  }, []);

  // Particle class
  class Particle {
    constructor(x, y, color) {
      this.x = x;
      this.y = y;
      this.color = color;
      this.size = Math.random() * 3 + 2;
      this.speedX = Math.random() * 6 - 3;
      this.speedY = Math.random() * 6 - 3;
      this.lifetime = 1;
      this.initialSize = this.size; // Store initial size
    }

    update() {
      this.x += this.speedX;
      this.y += this.speedY;
      this.lifetime -= 0.02;
      // Calculate size based on lifetime instead of continuous subtraction
      this.size = Math.max(0, this.initialSize * this.lifetime);
    }

    draw(ctx) {
      if (this.size <= 0) return; // Don't draw if size is 0 or negative

      ctx.fillStyle = this.color;
      ctx.globalAlpha = this.lifetime;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }
  }

  // Function to create explosion effect
  const createExplosion = (x, y, color) => {
    for (let i = 0; i < 20; i++) {
      particlesRef.current.push(new Particle(x, y, color));
    }
  };

  // Timer effect
  useEffect(() => {
    if (gameStarted && !gameOver && timeLeft > 0) {
      const timer = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);

      return () => clearInterval(timer);
    } else if (timeLeft === 0 && !gameOverHandled) {
      handleGameOver();
    }
  }, [timeLeft, gameOver, gameOverHandled, gameStarted]);

  // Handle game over
  const handleGameOver = () => {
    if (gameOverHandled) return;

    setGameOver(true);
    setGameOverHandled(true);

    const newScore = { name: playerName, score };
    const newHighScores = [...highScores, newScore]
      .sort((a, b) => b.score - a.score)
      .slice(0, 5);

    setHighScores(newHighScores);
    localStorage.setItem('highScores', JSON.stringify(newHighScores));
  };

  // State to store the current category
  const [currentCategory, setCurrentCategory] = useState(() => {
    const categories = Object.keys(AWS_ICON_CATEGORIES);
    const randomCategory = categories[Math.floor(Math.random() * categories.length)];
    return {
      category: AWS_ICON_CATEGORIES[randomCategory],
      displayName: randomCategory.split('_')
        .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(' '),
      text: `Shoot the ${randomCategory.split('_')
        .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(' ')} icons!`
    };
  });

  // State to track if the initial category has been set
  const [initialCategorySet, setInitialCategorySet] = useState(false);

  const newCategoryMission = async () => {
    // Guard against multiple simultaneous calls
    if (isChangingCategory.current) {
      console.log("Category change already in progress, skipping...");
      return;
    }

    if (isInitializing.current) {
      console.log("Game is still initializing, skipping category change");
      return;
    }

    console.log("newCategoryMission called");
    isChangingCategory.current = true;

    try {
      const categories = Object.keys(AWS_ICON_CATEGORIES);
      const randomCategory = categories[Math.floor(Math.random() * categories.length)];
      const newCategory = {
        category: AWS_ICON_CATEGORIES[randomCategory],
        displayName: randomCategory.split('_')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
          .join(' '),
        text: `Shoot the ${randomCategory.split('_')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
          .join(' ')} icons!`
      };

      // Set category and wait for state update
      await new Promise(resolve => {
        setCurrentCategory(newCategory);
        // Wait a tick to ensure state is updated
        setTimeout(resolve, 0);
      });

      // Then load the icons for this category
      console.log(`Loading icons for category: ${newCategory.displayName}`);
      await loadIcons();

    } catch (error) {
      console.error("Error in newCategoryMission:", error);
    } finally {
      isChangingCategory.current = false;
    }
  };

  // Modify the initialization effect
  useEffect(() => {
    const initializeGame = async () => {
      if (isInitializing.current) {
        console.log("Already initializing, skipping");
        return;
      }

      if (canvasRef.current && gameStarted && selectedRocket && !initialCategorySet) {
        console.log("Starting game initialization");
        isInitializing.current = true;

        try {
          const canvas = canvasRef.current;
          canvas.width = 1200;
          canvas.height = 800;

          const ctx = canvas.getContext('2d');
          ctx.imageSmoothingEnabled = true;

          // Initialize gun position
          initializeGun();

          console.log("Initializing game for the first time");
          await newCategoryMission();

          // Only set initialCategorySet to true after everything is done
          setInitialCategorySet(true);
          requestAnimationFrame(gameLoop);
        } catch (error) {
          console.error("Error initializing game:", error);
        } finally {
          isInitializing.current = false;
        }
      }
    };

    initializeGame();
  }, [gameStarted, selectedRocket]); // Remove initialCategorySet from dependencies

  // Remove or modify any other effects that might trigger category changes
  useEffect(() => {
    if (gameStarted && currentCategory && !isChangingCategory.current) {
      console.log('Current category:', currentCategory);
    }
  }, [currentCategory, gameStarted]);

  // Second effect for event listeners
  useEffect(() => {
    const canvas = canvasRef.current;

    const ROCKET_WIDTH = 50;
    const FIXED_ROCKET_Y = 550;

    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();

      // Calculate new X position
      let newX = e.clientX - rect.left - (gunRef.current.width / 2);

      // Add boundary checks
      newX = Math.max(-30, Math.min(newX, canvas.width - gunRef.current.width + 30));

      // Update gun position
      gunRef.current.x = newX;
    };

    const handleCanvasClick = () => {
      if (gameStarted && timeLeft > 0) {
        playSound('shoot');

        bulletsRef.current.push({
          x: gunRef.current.x + gunRef.current.width / 2 - 10,
          y: gunRef.current.y - 20,
        });
      }
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('click', handleCanvasClick);

    return () => {
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('click', handleCanvasClick);
    };
  }, [gameStarted]);

  // Clear both name and rocket selection when component mounts
  useEffect(() => {
    localStorage.removeItem('playerName');
    localStorage.removeItem('selectedRocket');
  }, []);

  // Add state for modal visibility
  const [showRocketModal, setShowRocketModal] = useState(true);

  // Add rocket options
  const rocketOptions = [
    { id: `${S3_ROCKET_PATH}/rocket1.png`, name: 'Modern Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket2.png`, name: 'Power Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket3.png`, name: 'Stealth Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket4.png`, name: 'Classic Rocket' },
  ];

  // Modify the rocket selection handler
  const handleRocketSelect = async (rocketId) => {
    console.log("Selecting rocket:", rocketId);
    setSelectedRocket(rocketId);
    localStorage.setItem('selectedRocket', rocketId);

    // Load the rocket image before starting the game
    try {
      console.log("Loading rocket image");
      rocketImage.current = new Image();
      await new Promise((resolve, reject) => {
        rocketImage.current.onload = resolve;
        rocketImage.current.onerror = reject;
        rocketImage.current.src = rocketId;
      });
      console.log("Rocket image loaded successfully");

      setShowRocketModal(false);
      setGameStarted(true);
    } catch (error) {
      console.error("Error loading rocket image:", error);
    }
  };

  // Add state for cheerleader messages
  const [cheerMessage, setCheerMessage] = useState('');
  const [showCheerMessage, setShowCheerMessage] = useState(false);

  // Add cheerleader messages for different situations
  const cheerleaderMessages = {
    goodShot: [
      "Great shot! You're an AWS Pro! 🌟",
      "Amazing cloud skills! Keep it up! 🎯",
      "You're on fire in the cloud! 🔥",
      "That's how AWS experts do it! 👏",
    ],
    combo: [
      "Cloud combo! 🎮",
      "You're scaling infinitely! ⚡",
      "What an AWS streak! 🌈",
    ],
    timeWarning: [
      "30 seconds left - you're highly available! ⏰",
      "Time for the final deployment! 💪",
      "Make every compute unit count! ⭐",
    ],
    encouragement: [
      "You've got this, cloud warrior! 🚀",
      "Keep going! You're AWS certified material! 🌟",
      "I believe in your cloud powers! 💫",
      "Show them your AWS expertise! 💪",
    ],
    highScore: [
      "New high score! You're going serverless! 🏆",
      "You're breaking cloud records! 🎖️",
      "Legendary AWS performance! 👑",
    ]
  };

  // Function to show a random message from a category
  const showCheerleaderMessage = (category) => {
    const messages = cheerleaderMessages[category];
    const randomMessage = messages[Math.floor(Math.random() * messages.length)];
    setCheerMessage(randomMessage);
    setShowCheerMessage(true);

    // Hide message after 3 seconds
    setTimeout(() => {
      setShowCheerMessage(false);
    }, 3000);
  };

  // Add periodic encouragement
  useEffect(() => {
    const encouragementInterval = setInterval(() => {
      if (timeLeft > 0 && Math.random() < 0.3) {
        showCheerleaderMessage('encouragement');
      }
    }, 10000);

    return () => clearInterval(encouragementInterval);
  }, [timeLeft]);

  // Add time warning messages
  useEffect(() => {
    if (timeLeft === 30) {
      showCheerleaderMessage('timeWarning');
    }
  }, [timeLeft]);

  // Add this function near other handlers (around line 440)
  const handleNameSubmit = (e) => {
    e.preventDefault();
    if (tempPlayerName.trim().length < 2) {
      setNameError('Name must be at least 2 characters long');
      return;
    }
    if (tempPlayerName.trim().length > 15) {
      setNameError('Name must be less than 15 characters');
      return;
    }
    setPlayerName(tempPlayerName.trim());
    localStorage.setItem('playerName', tempPlayerName.trim());
    setShowNameModal(false);
  };

  return (
    <div className="gameCanvas-container">
      <h1 className="gameCanvas-game-title">AWS Cloud Shooter</h1>
      <div className="gameCanvas-game-content">
        <div className="gameCanvas-canvas-wrapper">
          <canvas ref={canvasRef} className="gameCanvas-game-canvas" />
        </div>
        <div className="gameCanvas-instruction-panel">
          <div className="gameCanvas-player-info">
            <div className="gameCanvas-player-name">
              Player: {playerName}
            </div>
            <div className="gameCanvas-score-display">
              <span role="img" aria-label="alien">👾</span>{' '}
              Score: {score}{' '}
              <span role="img" aria-label="joystick">🕹️</span>

              {soundsLoaded && Object.values(sounds.current).some(sound => sound) && (
                <button 
                  className="gameCanvas-sound-toggle"
                  onClick={toggleMute}
                  aria-label="Toggle sound"
                >
                  {isMuted ? '🔇' : '🔊'}
                </button>
              )}
            </div>
          </div>

          <div className="gameCanvas-timer-display">
            Time: {timeLeft}s
          </div>

          <div className="gameCanvas-score-explanation">
            <h4>How to Score:</h4>
            <ul>
            <li>• Hit correct icon: +5 points</li>
            <li>• Height bonus: up to +20</li>
            <li>• Wrong hit: -5 points</li>
            <li>• Tip: Shoot icons as high as possible!</li>
            </ul>
          </div>

          <div className="gameCanvas-high-scores">
          <h4>High Scores</h4>
          <ul>
            {highScores.map((entry, index) => (
              <li key={index}>
                <span className="gameCanvas-high-score-name">{entry.name}:</span> {entry.score}
              </li>
            ))}
          </ul>
        </div>

          <div className="gameCanvas-mission-container">
            <h3 className="gameCanvas-mission-title">
              Current Mission
            </h3>

            <div className="gameCanvas-mission-text">
              {currentCategory?.text}
            </div>
          </div>
        </div>
      </div>

      {showRocketModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-rocket-selection-modal">
            <h2>Choose Your Rocket</h2>
            <div className="gameCanvas-rocket-grid">
              {rocketOptions.map((rocket) => (
                <div 
                  key={rocket.id} 
                  className={`gameCanvas-rocket-option ${selectedRocket === rocket.id ? 'selected' : ''}`}
                  onClick={() => handleRocketSelect(rocket.id)}
                >
                  <img 
                    //src={`icons/${rocket.id}`} 
                    src={rocket.id} 
                    alt={rocket.name}
                  />
                  <p>{rocket.name}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {gameOver && (
        <div className="gameCanvas-game-over">
          <h3>Game Over!</h3>
          <button onClick={() => window.location.reload()}>
            Play Again
          </button>
        </div>
      )}

      {showCheerMessage && (
        <div className="gameCanvas-cheerleader-container">
          <div className="gameCanvas-cheerleader-character">
            <img src={`${S3_BUCKET_URL}/games/utilities/cheerleader.png`} alt="Cheerleader" />
          </div>
          <div className="gameCanvas-cheer-message">
            {cheerMessage}
          </div>
        </div>
      )}

      {showNameModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-modal">
            <h2>Welcome to AWS Cloud Shooter!</h2>
            <p>Enter your name to start the game:</p>
            <form onSubmit={handleNameSubmit}>
              <input
                type="text"
                value={tempPlayerName}
                onChange={(e) => {
                  setTempPlayerName(e.target.value);
                  setNameError('');
                }}
                placeholder="Your name"
                className="gameCanvas-name-input"
                autoFocus
              />
              {nameError && <div className="gameCanvas-name-error">{nameError}</div>}
              <button type="submit" className="gameCanvas-start-button">
                Start Game
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameCanvas;
